Method.Source:
private void calcValues()
{
	LicensingEntitlementObjects                 licensingEntitlementObjects;
	if (this.EntitlementObject && ! this.AOTName)
	{
		select licensingEntitlementObjects
			where licensingEntitlementObjects.RecId == this.EntitlementObject;

		this.AotName           = licensingEntitlementObjects.AotName;
		this.SecurableType     = licensingEntitlementObjects.SecurableType;
	}
}

public static boolean exists(RefRecId   _entitlementObject,
                             TableName  _tableName)
{
    boolean res;
    ;
    if (_entitlementObject && _tableName)
    {
        res = (select firstonly RecId from DEVLicenseTablesObjectLink
                where DEVLicenseTablesObjectLink.EntitlementObject  == _entitlementObject &&
                      DEVLicenseTablesObjectLink.TableName          == _tableName).RecId != 0;
    }

    return res;
}

    public static void populate()
	{
		DEVLicenseElementUsageLog  licenseElementUsageLog;
        DEVLicenseTablesObjectLink  tablesObjectLink;

		while select licenseElementUsageLog
		group by AOTName, SecurableType
		where licenseElementUsageLog.SecurableType == SecurableType::MenuItemDisplay
        {

            str          formName;
            int          i;

            MenuFunction menuFunction = new MenuFunction(licenseElementUsageLog.AOTName, MenuItemType::Display);
            if (menuFunction.objectType() != MenuItemObjectType::Form)
            {
                continue;
            }


            formName = menuFunction.object();

            if (!formName)
            {
                continue;
                }
            //Microsoft.Dynamics.Ax.Xpp.MetadataSupport::CreateSqlConnection()

            Microsoft.Dynamics.AX.Metadata.MetaModel.AxForm  formMetadata =  Microsoft.Dynamics.Ax.Xpp.MetadataSupport::GetForm(formName);
            if (!formMetadata)
            {
                continue;
            }
            LicensingEntitlementObjects                 licensingEntitlementObjects;
			select firstonly licensingEntitlementObjects
				order by RecId
				where licensingEntitlementObjects.AotName == licenseElementUsageLog.AOTName &&
				licensingEntitlementObjects.SecurableType == licenseElementUsageLog.SecurableType;
            if (! licensingEntitlementObjects.RecId)
            {
			   continue;
			}

            Microsoft.Dynamics.AX.Metadata.MetaModel.AxFormDataSource dsMetadata;

            // Iterate datasources
            for (i = 0; i < formMetadata.DataSourceCount(); i++)
            {
                dsMetadata = formMetadata.GetDataSource(i);

                int tableId = tableName2Id(dsMetadata.Table);

                DictTable dictTable = new DictTable(tableId);
                if (! dictTable.isTempDb() && ! dictTable.isMap() && ! dictTable.isView() && ! dictTable.isTmp())
				{

                    tablesObjectLink.EntitlementObject = licensingEntitlementObjects.RecId;
                    tablesObjectLink.AotName           = licensingEntitlementObjects.AotName;
                    tablesObjectLink.SecurableType     = licensingEntitlementObjects.SecurableType;
                    tablesObjectLink.TableName = dictTable.name();

                    if (! DEVLicenseTablesObjectLink::exists(tablesObjectLink.EntitlementObject, tablesObjectLink.TableName))
                    {
						tablesObjectLink.insert();
                    }
                }
            }
        }

	}
